            out_list = ['delMatterFabric']
            break;
    
        case "setWifi":
            out_list = ['setWifi']
            break;
    
        case "getWifi":
            out_list = ['getWifi']
            break;
            
        case "registerHC":
            out_list = ['registerHC']
            break;
        
        case "startScan":
