function parseDeviceUpdate(msg) {

    var result = [];

    if (!msg.params) return result;

    for (var deviceName in msg.params) {
        if (!msg.params.hasOwnProperty(deviceName)) continue;

        var arr = msg.params[deviceName];
        if (!arr || !arr.length) continue;

        var payload = arr[0];
        var values = payload.values || {};
        var ts = payload.ts;

        var listMessage = [];

        if (values.hasOwnProperty("stt")) {

            listMessage.push({
                active: values.stt === 1,
                msgType: "POST_ATTRIBUTES_REQUEST"
            });

            var telemetry = {};
            for (var k in values) {
                if (values.hasOwnProperty(k)) {
                    telemetry[k] = values[k];
                }
            }
            telemetry.ts = ts;
            telemetry.msgType = "POST_TELEMETRY_REQUEST";

            listMessage.push(telemetry);

        } else {

            var data = {};
            for (var key in values) {
                if (values.hasOwnProperty(key)) {
                    data[key] = values[key];
                }
            }

            if (values.hasOwnProperty("onoff")) {
                data.ts = ts;
            }

            data.msgType = "POST_TELEMETRY_REQUEST";
            listMessage.push(data);
        }

        result.push({
            devId: deviceName,
            listMessage: listMessage
        });
    }

    return result;
}

msg = parseDeviceUpdate(msg)
return {
    msg: msg,
    metadata: metadata,
    msgType: msgType
};

