function buildDeviceUpdatePayload(inputData) {

  var currentTs = new Date().getTime();

  var output = {
    method: "deviceUpdate",
    params: {}
  };

  if (!inputData || !inputData.dataResponse || !inputData.dataResponse.length) {
    return output;
  }

  for (var i = 0; i < inputData.dataResponse.length; i++) {

    var item = inputData.dataResponse[i];

    if (item && item.entityName) {
      output.params[item.entityName] = [
        {
          ts: currentTs,
          values: {
            stt: 0
          }
        }
      ];
    }
  }

  return output;
}

